    /**
     * Get all of WDSEL's bit fields.
     *
     * (read-write) Set to 1 if the watchdog should reset this
     */
    inline void get_WDSEL(bool &PROC_COLD, bool &OTP, bool &ROSC, bool &XOSC,
                          bool &RESETS, bool &CLOCKS, bool &PSM_READY,
                          bool &BUSFABRIC, bool &ROM, bool &BOOTRAM,
                          bool &SRAM0, bool &SRAM1, bool &SRAM2, bool &SRAM3,
                          bool &SRAM4, bool &SRAM5, bool &SRAM6, bool &SRAM7,
                          bool &SRAM8, bool &SRAM9, bool &XIP, bool &SIO,
                          bool &ACCESSCTRL, bool &PROC0, bool &PROC1) volatile
    {
        uint32_t curr = WDSEL;

        PROC_COLD = curr & 1u;
        OTP = curr & (1u << 1u);
        ROSC = curr & (1u << 2u);
        XOSC = curr & (1u << 3u);
        RESETS = curr & (1u << 4u);
        CLOCKS = curr & (1u << 5u);
        PSM_READY = curr & (1u << 6u);
        BUSFABRIC = curr & (1u << 7u);
        ROM = curr & (1u << 8u);
        BOOTRAM = curr & (1u << 9u);
        SRAM0 = curr & (1u << 10u);
        SRAM1 = curr & (1u << 11u);
        SRAM2 = curr & (1u << 12u);
        SRAM3 = curr & (1u << 13u);
        SRAM4 = curr & (1u << 14u);
        SRAM5 = curr & (1u << 15u);
        SRAM6 = curr & (1u << 16u);
        SRAM7 = curr & (1u << 17u);
        SRAM8 = curr & (1u << 18u);
        SRAM9 = curr & (1u << 19u);
        XIP = curr & (1u << 20u);
        SIO = curr & (1u << 21u);
        ACCESSCTRL = curr & (1u << 22u);
        PROC0 = curr & (1u << 23u);
        PROC1 = curr & (1u << 24u);
    }

    /**
     * Set all of WDSEL's bit fields.
     *
     * (read-write) Set to 1 if the watchdog should reset this
     */
    inline void set_WDSEL(bool PROC_COLD, bool OTP, bool ROSC, bool XOSC,
                          bool RESETS, bool CLOCKS, bool PSM_READY,
                          bool BUSFABRIC, bool ROM, bool BOOTRAM, bool SRAM0,
                          bool SRAM1, bool SRAM2, bool SRAM3, bool SRAM4,
                          bool SRAM5, bool SRAM6, bool SRAM7, bool SRAM8,
                          bool SRAM9, bool XIP, bool SIO, bool ACCESSCTRL,
                          bool PROC0, bool PROC1) volatile
    {
        uint32_t curr = WDSEL;

        curr &= ~(0b1u);
        curr |= (PROC_COLD & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (OTP & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (ROSC & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (XOSC & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (RESETS & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (CLOCKS & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (PSM_READY & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (BUSFABRIC & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (ROM & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (BOOTRAM & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (SRAM0 & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (SRAM1 & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (SRAM2 & 0b1u) << 12u;
        curr &= ~(0b1u << 13u);
        curr |= (SRAM3 & 0b1u) << 13u;
        curr &= ~(0b1u << 14u);
        curr |= (SRAM4 & 0b1u) << 14u;
        curr &= ~(0b1u << 15u);
        curr |= (SRAM5 & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (SRAM6 & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (SRAM7 & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (SRAM8 & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (SRAM9 & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (XIP & 0b1u) << 20u;
        curr &= ~(0b1u << 21u);
        curr |= (SIO & 0b1u) << 21u;
        curr &= ~(0b1u << 22u);
        curr |= (ACCESSCTRL & 0b1u) << 22u;
        curr &= ~(0b1u << 23u);
        curr |= (PROC0 & 0b1u) << 23u;
        curr &= ~(0b1u << 24u);
        curr |= (PROC1 & 0b1u) << 24u;

        WDSEL = curr;
    }

